script.text:
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {sender.add_onResponseComplete(on$Filter$ResponseComplete);}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, k = new Array();
      g._fromDate = f.getItemValue('ngay_tu');
      g._toDate = f.getItemValue('ngay_den');
      g._periodCode = f.getItemValue('ma_dot');

      if (g._fromDate) Array.add(k, {Name: 'ngay_tu', Opr: '>=', Value: g._fromDate, Type: 'DateTime', Ignore: false});
			if (g._toDate) Array.add(k, {Name: 'ngay_tu', Opr: '<=', Value: g._toDate, Type: 'DateTime', Ignore: false});
	    if (g._periodCode) Array.add(k, {Name: 'ma_dot', Opr: '=', Value: g._periodCode, Type: 'String', Ignore: false});
      g.set_externalKey(k);
      break;
    default:
      break;
  }
}
/* </flatten> */
